bindings = {}

def is_var(x):
    return isinstance(x, str) and x.startswith("?")

def lookup(x):
    while is_var(x) and x in bindings:
        x = bindings[x]
    return x

def unify(e, f):
    e = lookup(e)
    f = lookup(f)
    if e == f:
        return True
    if is_var(e):
        bindings[e] = f
        return True
    if is_var(f):
        bindings[f] = e
        return True
    if not isinstance(e, list) or not isinstance(f, list):
        return False
    if len(e) != len(f):
        return False
    for i in range(len(e)):
        if not unify(e[i], f[i]):
            return False
    return True

left = ["?x", "?x"]
right = [["a", "?y", "c"], ["a", "b", "?z"]]
print(unify(left, right))
